#!/usr/bin/env python3
"""Generate all he_fix_*_he_only.json files with pure Hebrew."""
import json
import re
from pathlib import Path

BASE = Path(__file__).resolve().parent.parent / "data" / "translation-catalog"
OUT = BASE / "human"

MIXED_RE = re.compile(r"[\u0590-\u05FF]+[A-Za-z]+|[A-Za-z]+[\u0590-\u05FF]+")


def check_pure(strings, label):
    bad = []
    for i, s in enumerate(strings):
        for m in MIXED_RE.finditer(s):
            g = m.group()
            if "HebrewCalendar" in g:
                continue
            bad.append((i + 1, g))
    if bad:
        raise SystemExit(f"{label} mixed Latin/Hebrew: {bad}")


def write_batch(name, strings):
    check_pure(strings, name)
    keys = json.loads((BASE / f"_keys_{name}.json").read_text(encoding="utf-8"))
    assert len(strings) == len(keys), f"{name}: {len(strings)} != {len(keys)}"
    path = OUT / f"{name}_he_only.json"
    path.write_text(json.dumps({"he": strings}, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    print(f"OK {path.name}: {len(strings)} strings")


# Common terms (pure Hebrew)
