    + "\u05d9\u05e9 \u05dc\u05d4\u05d5\u05e1\u05d9\u05e3 \u05d2\u05dd \u05e9\u05dd \u05d9\u05e2\u05dc\u05d4 \u05d5\u05d9\u05d1\u05d5\u05d0.",
    '${yaalehVyavoFemaleAmidahLead("Shacharit")}\n\n${yaalehVyavoForgotShacharitOrMincha("Shacharit")}\n\n'
    + "\u05d0\u05dd \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05d1\u05e8\u05db\u05ea \u05d4\u05de\u05d6\u05d5\u05df \u05db\u05e9\u05d0\u05d5\u05db\u05dc\u05d9\u05dd \u05dc\u05d7\u05dd \u05d4\u05d9\u05d5\u05dd, "
